const squads = ['crm', 'projetos', 'obras', 'suporte', 'insights', 'financeiro'];
const reports = [];
for (const squad of squads) {
  const data = await $http.get(`/api/v1/${squad}/weekly-summary`);
  reports.push({ squad, ...data });
}
return reports;

const report = $input.first().json;
const pdf = await $http.post('/api/v1/reports/pdf', {
  title: report.title,
  content: report.content,
  template: 'weekly-executive'
}, { responseType: 'arraybuffer' });

// Upload to library
const formData = new FormData();
formData.append('file', new Blob([pdf], { type: 'application/pdf' }), `relatorio-semanal-${report.week}.pdf`);
formData.append('type', 'weekly_report');
formData.append('tags', 'semanal,executivo');

await $http.post('/api/v1/library/documents', formData);
return { ...report, pdfGenerated: true };

